// Comment API — public endpoint for blog comments
// GET  /api/comments?page=/en/posts/slug/  → list comments
// POST /api/comments                         → create comment

const MAX_BODY_CHARS = 5000;
const MAX_NAME_CHARS = 100;
const MAX_EMAIL_CHARS = 254;
const COMMENT_LIMIT = { windowSeconds: 10 * 60, count: 5 };

let schemaReady = null;

export function onRequest(context) {
  return handleCommentApi(context.request, context.env);
}

async function handleCommentApi(request, env) {
  try {
    await ensureDatabase(env);
    const url = new URL(request.url);
    const method = request.method.toUpperCase();

    if (method === "GET") {
      return listComments(env, url);
    }
    if (method === "POST") {
      return createComment(request, env);
    }
    return json({ error: "Method not allowed." }, { status: 405 });
  } catch (error) {
    return jsonError(error);
  }
}

async function listComments(env, url) {
  const page = (url.searchParams.get("page") || "").trim();
  if (!page) {
    throw httpError(400, "Missing page parameter.");
  }

  const rows = await env.DB.prepare(
    `SELECT id, author_name, body_markdown, created_at
       FROM comments
      WHERE page_path = ? AND deleted_at IS NULL
      ORDER BY created_at ASC
      LIMIT 200`
  ).bind(page).all();

  const comments = rows.results.map((row) => ({
    id: row.id,
    author_name: row.author_name || null,
    body_html: renderMarkdown(row.body_markdown),
    created_at: row.created_at,
  }));

  return json({ comments });
}

async function createComment(request, env) {
  let body;
  try {
    body = await request.json();
  } catch (_error) {
    throw httpError(400, "Expected JSON body.");
  }

  const page = (body.page || "").trim();
  const authorName = (body.author_name || "").trim() || null;
  const authorEmail = (body.author_email || "").trim() || null;
  const bodyMarkdown = (body.body || "").trim();

  if (!page) throw httpError(400, "Missing page field.");
  if (!bodyMarkdown) throw httpError(400, "Missing body field.");
  if (bodyMarkdown.length > MAX_BODY_CHARS) {
    throw httpError(400, `Comment body exceeds ${MAX_BODY_CHARS} characters.`);
  }
  if (authorName && authorName.length > MAX_NAME_CHARS) {
    throw httpError(400, `Name exceeds ${MAX_NAME_CHARS} characters.`);
  }
  if (authorEmail && authorEmail.length > MAX_EMAIL_CHARS) {
    throw httpError(400, `Email exceeds ${MAX_EMAIL_CHARS} characters.`);
  }
  if (authorEmail && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(authorEmail)) {
    throw httpError(400, "Invalid email format.");
  }

  // Honeypot check — hidden field should be empty
  if (body.website && body.website.trim()) {
    // Silently discard bot submissions — return fake success
    return json({ comment: { id: "fake", author_name: authorName, body_html: "", created_at: new Date().toISOString() } });
  }

  const ip = request.headers.get("cf-connecting-ip") || "unknown";
  await checkRateLimit(env, `comments:${ip}`, COMMENT_LIMIT);

  const id = crypto.randomUUID();
  const now = new Date().toISOString();

  await env.DB.prepare(
    `INSERT INTO comments (id, page_path, author_name, author_email, body_markdown, created_at)
     VALUES (?, ?, ?, ?, ?, ?)`
  ).bind(id, page, authorName, authorEmail, bodyMarkdown, now).run();

  const comment = {
    id,
    author_name: authorName,
    body_html: renderMarkdown(bodyMarkdown),
    created_at: now,
  };

  return json({ comment }, { status: 201 });
}

// ---------- Rate limiting ----------

async function checkRateLimit(env, keyPrefix, rule) {
  const bucket = Math.floor(Date.now() / 1000 / rule.windowSeconds);
  const key = `${keyPrefix}:${bucket}`;
  const windowStart = new Date(bucket * rule.windowSeconds * 1000).toISOString();

  const row = await env.DB.prepare(
    `INSERT INTO room_rate_limits (key, window_start, count)
     VALUES (?, ?, 1)
     ON CONFLICT(key) DO UPDATE SET count = count + 1
     RETURNING count`
  ).bind(key, windowStart).first();

  if (row.count > rule.count) {
    throw httpError(429, "Too many comments. Please wait before posting again.");
  }
}

// ---------- Database ----------

async function ensureDatabase(env) {
  if (schemaReady) return;
  const db = env.DB;
  await db.prepare(
    `CREATE TABLE IF NOT EXISTS comments (
      id TEXT PRIMARY KEY,
      page_path TEXT NOT NULL,
      author_name TEXT,
      author_email TEXT,
      body_markdown TEXT NOT NULL,
      created_at TEXT NOT NULL,
      deleted_at TEXT
    )`
  ).run();
  await db.prepare(
    `CREATE INDEX IF NOT EXISTS idx_comments_page
       ON comments (page_path, created_at ASC)
     WHERE deleted_at IS NULL`
  ).run();
  // Reuse room_rate_limits for rate limiting (created by room migration)
  schemaReady = true;
}

// ---------- Markdown rendering (constrained — no raw HTML, safe links only) ----------

function renderMarkdown(markdown) {
  const lines = String(markdown).replace(/\r\n/g, "\n").split("\n");
  const blocks = [];
  let paragraph = [];
  let list = [];
  let quote = [];
  let inCode = false;
  let code = [];

  function flushParagraph() {
    if (!paragraph.length) return;
    blocks.push(`<p>${renderInline(paragraph.join(" "))}</p>`);
    paragraph = [];
  }
  function flushList() {
    if (!list.length) return;
    blocks.push(`<ul>${list.map((item) => `<li>${renderInline(item)}</li>`).join("")}</ul>`);
    list = [];
  }
  function flushQuote() {
    if (!quote.length) return;
    blocks.push(`<blockquote>${quote.map((item) => `<p>${renderInline(item)}</p>`).join("")}</blockquote>`);
    quote = [];
  }
  function flushCode() {
    if (!code.length) return;
    blocks.push(`<pre><code>${escapeHtml(code.join("\n"))}</code></pre>`);
    code = [];
  }

  for (const line of lines) {
    if (/^\s*```/.test(line)) {
      if (inCode) { inCode = false; flushCode(); } else { flushParagraph(); flushList(); flushQuote(); inCode = true; }
      continue;
    }
    if (inCode) { code.push(line); continue; }
    if (!line.trim()) { flushParagraph(); flushList(); flushQuote(); continue; }

    const heading = line.match(/^(#{1,3})\s+(.+)$/);
    if (heading) {
      flushParagraph(); flushList(); flushQuote();
      blocks.push(`<h${heading[1].length + 1}>${renderInline(heading[2])}</h${heading[1].length + 1}>`);
      continue;
    }
    const listItem = line.match(/^\s*[-*]\s+(.+)$/);
    if (listItem) { flushParagraph(); flushQuote(); list.push(listItem[1]); continue; }
    const quoteLine = line.match(/^\s*>\s?(.+)$/);
    if (quoteLine) { flushParagraph(); flushList(); quote.push(quoteLine[1]); continue; }

    flushList(); flushQuote();
    paragraph.push(line.trim());
  }

  flushCode(); flushParagraph(); flushList(); flushQuote();
  return blocks.join("\n");
}

function renderInline(value) {
  const codeSegments = [];
  let escaped = escapeHtml(value).replace(/`([^`]+)`/g, (_match, code) => {
    const token = `�CODE${codeSegments.length}�`;
    codeSegments.push(`<code>${escapeHtml(code)}</code>`);
    return token;
  });
  escaped = escaped.replace(/\[([^\]]+)]\(([^)\s]+)\)/g, (_match, label, href) => {
    const decoded = href.replace(/&amp;/g, "&");
    if (!isSafeHref(decoded)) return label;
    return `<a href="${escapeAttribute(decoded)}" rel="nofollow noreferrer noopener" target="_blank">${label}</a>`;
  });
  escaped = escaped.replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>").replace(/\*([^*]+)\*/g, "<em>$1</em>");
  codeSegments.forEach((html, i) => { escaped = escaped.replace(`�CODE${i}�`, html); });
  return escaped;
}

function isSafeHref(value) {
  try { const url = new URL(value); return url.protocol === "https:" || url.protocol === "http:" || url.protocol === "mailto:"; } catch (_e) { return false; }
}

function escapeHtml(value) {
  return String(value).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#39;");
}

function escapeAttribute(value) {
  return escapeHtml(value).replace(/`/g, "&#96;");
}

// ---------- Response helpers ----------

function httpError(status, message) {
  const error = new Error(message);
  error.status = status;
  return error;
}

function jsonError(error) {
  const status = Number(error.status || 500);
  const message = status >= 500 ? error.message || "Internal server error." : error.message;
  return json({ error: message }, { status });
}

function json(payload, init = {}) {
  const headers = new Headers(init.headers || {});
  headers.set("content-type", "application/json; charset=utf-8");
  headers.set("cache-control", "no-store");
  return new Response(JSON.stringify(payload), { ...init, headers });
}
